Method.Source:
/// <summary>
/// Extension of the <c>init</c> method for the ETGSPAIN model.
/// </summary>
/// <remarks>
/// This code is used to show/hide features in Spanish companies.
/// </remarks>
public void init()
{
    next init();
    NoYesId currentCompanyIsSpanishCompany  = CurrentCompanyIsSpanishCompany();

    this.design().controlName(formControlStr(InventTrans, ETGSPAINInventTrans_InventPackingSlipTransitId)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(InventTrans, ETGSPAINInventTransApplication_PurchApplicationQty)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(InventTrans, ETGSPAINInventTrans_InventLicensePlate)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(InventTrans, ETGSPAINInventTransApplication_SalesApplicationQty)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(InventTrans, ETGSPAINInventTransApplication_DateApplicationQty)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(InventTrans, ETGSPAINInventTrans_SalesCustomerWithdrawalDate)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(InventTrans, ETGSPAINInventTrans_CustSalesReference)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(InventTrans, ETGSPAINUnsoldInventTrans_UnsoldQty)).visible(currentCompanyIsSpanishCompany);
}
